def _compute_dir_fingerprint(root: Path) -> str:
    h = hashlib.sha256()
    if not root.exists():
        return ""
    for p in sorted(root.rglob("*"), key=lambda x: str(x)):
        rel = str(p.relative_to(root)).replace("\\", "/")
