def fetch_to_local(model_uri: str, cache_dir: Path) -> tuple[Path, dict]:
    resolved_uri, resolved_version = _resolve_latest_uri(model_uri)
    src = _parse_model_source(resolved_uri)
    u = src["parsed"]
    scheme = src["scheme"]

    meta = {
        "requested_uri": model_uri,
        "resolved_uri": resolved_uri,
        "resolved_version": resolved_version,
        "fetched_at": int(time.time()),
    }

    with tempfile.TemporaryDirectory(prefix="model_fetch_") as td:
        tmp = Path(td)
        staging = tmp / "staging"
        staging.mkdir(parents=True, exist_ok=True)

        if scheme == "file":
            p = Path(unquote(u.path))
            if not p.exists():
                raise ModelLoaderError(f"Local path not found: {p}")
            if p.is_dir():
                shutil.copytree(p, staging / "model", dirs_exist_ok=True)
            else:
                (staging / "model").mkdir(parents=True, exist_ok=True)
                shutil.copy2(p, staging / "model" / p.name)
        elif scheme in ("http", "https"):
            (staging / "model").mkdir(parents=True, exist_ok=True)
            _download_http(resolved_uri, staging / "model")
        elif scheme == "s3":
            bucket = u.netloc
            key = u.path.lstrip("/")
            region = parse_qs(u.query).get("region", [None])[0] or os.getenv("AWS_REGION") or os.getenv("AWS_DEFAULT_REGION")
            (staging / "model").mkdir(parents=True, exist_ok=True)
            _download_s3(bucket, key, staging / "model", region)
        elif scheme == "gs":
            bucket = u.netloc
            prefix = u.path.lstrip("/")
            (staging / "model").mkdir(parents=True, exist_ok=True)
            _download_gcs(bucket, prefix, staging / "model")
        elif scheme in ("az", "azure"):
            container = u.netloc
            prefix = u.path.lstrip("/")
            conn_str = os.getenv("AZURE_STORAGE_CONNECTION_STRING")
            account_url = os.getenv("AZURE_STORAGE_ACCOUNT_URL")
            (staging / "model").mkdir(parents=True, exist_ok=True)
            _download_azure(container, prefix, staging / "model", conn_str, account_url)
        else:
            raise ModelLoaderError(f"Unsupported scheme: {scheme}")

        model_root = staging / "model"
        if not model_root.exists():
            raise ModelLoaderError("Download did not produce a model directory")

        meta_path = staging / "meta.json"
        meta_path.write_text(json.dumps(meta, indent=2), encoding="utf-8")

        new_fp = _compute_dir_fingerprint(model_root)
        meta["fingerprint"] = new_fp
        meta_path.write_text(json.dumps(meta, indent=2), encoding="utf-8")

        target = cache_dir / "current"
        new_dir = tmp / "new_current"
        shutil.copytree(staging, new_dir, dirs_exist_ok=True)
        _atomic_replace_dir(new_dir, target)

    return cache_dir / "current" / "model", meta


def load_model(model_dir: Path):
    model_dir = model_dir.resolve()
    if not model_dir.exists():
        raise ModelLoaderError(f"Model directory missing: {model_dir}")

    candidates = [
        ("TorchScript", model_dir / "model.pt"),
        ("TorchScript", model_dir / "model.ts"),
        ("PyTorch", model_dir / "model.pth"),
        ("ONNX", model_dir / "model.onnx"),
        ("Joblib", model_dir / "model.joblib"),
        ("Pickle", model_dir / "model.pkl"),
    ]

    found = None
    for kind, path in candidates:
        if path.exists() and path.is_file():
            found = (kind, path)
            break

    if found is None:
        files = [str(p.relative_to(model_dir)).replace("\\", "/") for p in model_dir.rglob("*") if p.is_file()]
        raise ModelLoaderError(
            "No known model artifact found. Expected one of: "
            + ", ".join(str(p.name) for _, p in candidates)
            + ". Files present: "
            + (", ".join(files[:50]) + (" ..." if len(files) > 50 else ""))
        )

    kind, path = found
    if kind in ("TorchScript", "PyTorch"):
        try:
            import torch
        except Exception as e:
            raise ModelLoaderError(f"torch is required to load {kind} models: {e}")
        obj = torch.jit.load(str(path), map_location="cpu") if kind == "TorchScript" else torch.load(str(path), map_location="cpu")
        return {"type": kind, "path": str(path), "object": obj}

    if kind == "ONNX":
        try:
            import onnxruntime as ort
        except Exception as e:
            raise ModelLoaderError(f"onnxruntime is required to load ONNX models: {e}")
        sess = ort.InferenceSession(str(path), providers=["CPUExecutionProvider"])
        return {"type": kind, "path": str(path), "object": sess}

    if kind == "Joblib":
        try:
            import joblib
        except Exception as e:
            raise ModelLoaderError(f"joblib is required to load Joblib models: {e}")
        obj = joblib.load(str(path))
        return {"type": kind, "path": str(path), "object": obj}

    if kind == "Pickle":
        import pickle
        with open(path, "rb") as f:
            obj = pickle.load(f)
        return {"type": kind, "path": str(path), "object": obj}

    raise ModelLoaderError(f"Unhandled model type: {kind}")


def main():
    model_uri = os.getenv("MODEL_URI") or os.getenv("MODEL_PATH")
    if not model_uri:
        print("MODEL_URI (or MODEL_PATH) env var is required", file=sys.stderr)
        sys.exit(2)

    cache_dir = Path(os.getenv("MODEL_CACHE_DIR", "/tmp/model_cache")).resolve()
    cache_dir.mkdir(parents=True, exist_ok=True)

    logger.info("Fetching model: %s", model_uri)
    model_dir, meta = fetch_to_local(model_uri, cache_dir)
    logger.info("Model fetched to: %s", str(model_dir))
    logger.info("Resolved URI: %s", meta.get("resolved_uri"))

    logger.info("Loading model from: %s", str(model_dir))
    loaded = load_model(model_dir)
    logger.info("Loaded model type: %s path: %s", loaded["type"], loaded["path"])

    keep_running = os.getenv("KEEP_RUNNING", "true").lower() in ("1", "true", "yes", "y")
    if keep_running:
        logger.info("Ready. KEEP_RUNNING=true; sleeping.")
        while True:
            time.sleep(3600)


if __name__ == "__main__":
    main()